function processCheckout(cart: Cart, user: User): Receipt {
  const subtotal = cart.items.reduce((s, i) => s + i.price, 0);
  const discount = user.isPremium ? subtotal * 0.1 : 0;
  const taxed = (subtotal - discount) * 1.08;
  if (cart.items.length === 0) throw new Error('Empty cart');
  reserveInventory(cart.items);
  const payment = chargeCard(user.cardToken, taxed);
  if (!payment.ok) releaseInventory(cart.items);
  sendConfirmationEmail(user.email, taxed);
  logCheckout(user.id, cart.items.length, taxed);
  return { total: taxed, paymentId: payment.id };
}

class BillingService {
  finalize(order: Order): Invoice {
    this.assertOrder(order);
    const subtotal = this.sumItems(order.items);
    const coupon = this.resolveCoupon(order.couponCode);
    const total = this.applyTax(subtotal - coupon.amount, order.country);
    this.audit(order.id, total);
    this.repo.saveInvoice(order.id, total, coupon.code);
    this.analytics.track('invoice_created', { orderId: order.id, total });
    this.mailer.send(order.email, this.renderInvoiceEmail(order, total));
    return { orderId: order.id, total };
  }
}

