class InvoiceFlow {
  run(o: Order): void {
    const total = this.calc(o);
    this.repo.save(o.id, total);
    this.mailer.send(o.email, this.template(o, total));
    this.metrics.record(o.id, total);
    this.audit.log('invoice', o.id, total);
  }
}
